const items = $input.all();

const webhookItem = $('When Webhook Received').first();

if (!webhookItem || !webhookItem.binary) {
  throw new Error("No binary file was found in the Webhook node.");
}

const binaryKey = Object.keys(webhookItem.binary)[0];
const binaryFile = webhookItem.binary[binaryKey];

for (const item of items) {
  item.binary = {
    audio: binaryFile
  };
}

return items;
